Almost similar to subarray sum equals k
```
int maximumScore(vector<vector<int> > arr, int n, int t, int k){

    vector<vector<int> > dp(n+1, vector<int>(t+1, 0));

    for(int i = 1;i<=n;++i){
        for(int j = 1; j<=t;++j){
            if (arr[i-1][0] <= j){
                dp[i][j] = max(arr[i-1][1] + dp[i-1][j-arr[i-1][0]], dp[i-1][j]);
            }
            else 
                dp[i][j] = dp[i-1][j];
        }
    }

    int mintime = INT_MAX;
    for(int i = 0; i <n+1; ++i){
        auto it = lower_bound(dp[i].begin(), dp[i].end(), k);
        if (it != dp[i].end()){
            mintime = min(mintime, (int) distance(dp[i].begin(), it));
        }
    }
    return mintime == INT_MAX?-1:mintime;

}

int main() {
    vector<vector<int> > arr = {{12,10},
                                {16,10},
                                {20,10},
                                {24,10},
                                {8,3}};
    int n = 5, t = 40, k = 21;
    std::cout << maximumScore(arr,n,t,k);
}
